            // All numbers are even. We must use subtraction (Even - X = Odd => X must be Odd).
            // If there are no odd numbers, we cannot achieve an odd result for any element.
            false
        } else if even_nums_indices.is_empty() {
            // All numbers are odd. Trivial success.
            true
