            // Mixed parity. For every even number nums1[i], we must find an odd nums1[j] such that nums1[i] - nums1[j] >= 1.

            let odd_nums: Vec<i64> = nums1.iter().copied().filter(|&x| x % 2 != 0).collect();

            for &i in even_nums_indices.iter() {
                let val_i = nums1[i];
                let mut can_transform = false;

                for &val_j_odd in odd_nums.iter() {
                    if val_i - val_j_odd >= 1 {
                        // We need to ensure j != i, but since val_i is even and val_j_odd is odd, they are different values, 
                        // and since nums1 has unique elements, the indices are different unless the odd number we are subtracting
