                        // Since we are guaranteed nums1[j] != nums1[i], we just need to check the value condition.
                        can_transform = true;
                        break;
                    }
                }
                if !can_transform {
                    return false;
                }
            }
            true
        }
    };

    can_be_all_even || can_be_all_odd
}
